export default function FicheZoo() {
  const [theme, setTheme] = useState<"light" | "dark">("light");

  useEffect(() => {
    const saved = localStorage.getItem("fiche-theme") as "light" | "dark" | null;
    if (saved) setTheme(saved);
  }, []);

  const toggleTheme = () => {
    const next = theme === "light" ? "dark" : "light";
    setTheme(next);
    localStorage.setItem("fiche-theme", next);
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: theme === "dark" ? "#0d1520" : "#f0f0f0",
        position: "relative",
      }}
    >
      <div
        onClick={toggleTheme}
        role="button"
        aria-label="Basculer le thème"
        style={{
          position: "fixed",
          top: "16px",
          right: "16px",
          zIndex: 1000,
          display: "flex",
          alignItems: "center",
          gap: "8px",
          background: theme === "dark" ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.08)",
          border: "1px solid rgba(200,241,53,0.25)",
          borderRadius: "999px",
          padding: "6px 14px",
          cursor: "pointer",
        }}
      >
        <span style={{ fontSize: "14px" }}>{theme === "dark" ? "☀️" : "🌙"}</span>
        <span
          style={{
            fontSize: "11px",
            fontWeight: 500,
            color: theme === "dark" ? "#c8f135" : "#3B6D11",
          }}
        >
          {theme === "dark" ? "Mode clair" : "Mode sombre"}
        </span>
      </div>

      <div dangerouslySetInnerHTML={{ __html: ficheHTML }} />
    </div>
  );
}
